content:
/* 文章封面左侧小缩略图 - 强制覆盖主题样式 */

/* 整个卡片：flex 布局，高度自动等于封面图高度 */
#recent-posts .recent-post-item {
  display: flex !important;
  flex-direction: row !important;
  align-items: stretch !important;
  height: auto !important;
  padding: 0 !important;
  margin-bottom: 16px !important;
  overflow: visible !important;
}

/* 封面图 120×120px */
#recent-posts .recent-post-item .post_cover {
  width: 120px !important;
  min-width: 120px !important;
  height: 120px !important;
  min-height: 120px !important;
  max-height: 120px !important;
  flex-shrink: 0 !important;
  order: 0 !important;
  border-radius: 8px !important;
  overflow: hidden !important;
}

/* 强制 .right 也变左侧，不交替 */
#recent-posts .recent-post-item .post_cover.right {
  order: 0 !important;
}

#recent-posts .recent-post-item .post_cover .post-bg {
  width: 120px !important;
  height: 120px !important;
  object-fit: cover !important;
  display: block !important;
  position: static !important;
}

/* 禁止 hover 放大动画 */
#recent-posts .recent-post-item:hover .post-bg {
  transform: none !important;
}

/* 文字信息区域：撑满剩余高度，与封面图对齐 */
#recent-posts .recent-post-item > .recent-post-info {
  flex: 1 !important;
  min-width: 0 !important;
  padding: 8px 12px !important;
  width: auto !important;
  display: flex !important;
  flex-direction: column !important;
  justify-content: center !important;
  align-self: stretch !important;
}

/* 标题缩小，配合小图 */
#recent-posts .recent-post-item .recent-post-info .article-title {
  font-size: 1.05em !important;
  line-height: 1.4 !important;
  margin: 0 !important;
}

/* 日期、分类、摘要也收紧 */
#recent-posts .recent-post-item .recent-post-info .article-meta {
  margin-top: 4px !important;
}

/* 文章正文标题字号缩小2号 */
.post-content h1 { font-size: 1.4em !important; }
.post-content h2 { font-size: 1.2em !important; }
.post-content h3 { font-size: 1.0em !important; }

/* 移动端：封面图缩小 */
@media (max-width: 768px) {
  #recent-posts .recent-post-item .post_cover {
    width: 80px !important;
    min-width: 80px !important;
    height: 80px !important;
    min-height: 80px !important;
    max-height: 80px !important;
  }
  #recent-posts .recent-post-item .post_cover .post-bg {
    width: 80px !important;
    height: 80px !important;
  }
  #recent-posts .recent-post-item > .recent-post-info {
    padding: 6px 10px !important;
  }
  #recent-posts .recent-post-item .recent-post-info .article-title {
    font-size: 1em !important;
  }
}
